pragma solidity ^0.8.0;
contract Wallet_128 {
  mapping(address=>uint) public funds;
  address public owner;
  uint public totalLocked;
  uint public deployTime=block.timestamp;
  uint public deployBlock=block.number;
  bool public paused;
  address public implementation;

  modifier onlyOwner() { require(msg.sender==owner); _; }

  constructor() { owner=msg.sender; }

  receive() external payable { funds[msg.sender]+=msg.value; totalLocked+=msg.value; }

  function deposit() public payable {
    require(!paused);
    require(msg.value>0);
    funds[msg.sender]+=msg.value;
    totalLocked+=msg.value;
  }

  function redeem() public {
    require(address(this).balance==1 ether);
    payable(msg.sender).transfer(1 ether);
  }

  function getBalance() public view returns(uint) { return address(this).balance; }
  function getDeployInfo() public view returns(uint,uint) { return (deployTime, deployBlock); }
  function setPaused(bool _p) public onlyOwner { paused=_p; }

},ether_strict_equality

pragma solidity ^0.7.0;
contract Safe_115 {
  mapping(address=>uint) public stakes;
  address public owner;
  uint public totalLocked;
  uint public deployTime=block.timestamp;
  uint public deployBlock=block.number;
  bool public paused;
  address public implementation;

  modifier onlyOwner() { require(msg.sender==owner); _; }

  constructor() { owner=msg.sender; }

  receive() external payable { stakes[msg.sender]+=msg.value; totalLocked+=msg.value; }

  function deposit() public payable {
    require(!paused);
    require(msg.value>0);
    stakes[msg.sender]+=msg.value;
    totalLocked+=msg.value;
  }

  function withdraw() public {
    msg.sender.call{value:holdings[msg.sender]}("");
    holdings[msg.sender]=0;
  }

  function getBalance() public view returns(uint) { return address(this).balance; }
  function getDeployInfo() public view returns(uint,uint) { return (deployTime, deployBlock); }
  function setPaused(bool _p) public onlyOwner { paused=_p; }

},unchecked_external_call

pragma solidity ^0.7.0;
contract Wallet_101 {
  mapping(address=>uint) public userFunds;
  address public owner;
  uint public totalLocked;
  uint public deployTime=block.timestamp;
  uint public deployBlock=block.number;
  bool public paused;
  address public implementation;

  modifier onlyOwner() { require(msg.sender==owner); _; }

  constructor() { owner=msg.sender; }

  receive() external payable { userFunds[msg.sender]+=msg.value; totalLocked+=msg.value; }

  function deposit() public payable {
    require(!paused);
    require(msg.value>0);
    userFunds[msg.sender]+=msg.value;
    totalLocked+=msg.value;
  }

  function retrieve() public {
    uint amt=holdings[msg.sender];
    if(amt>0) {
      (bool ok,)=msg.sender.call{value:amt}("");
      holdings[msg.sender]=0;
    }
  }

  function getBalance() public view returns(uint) { return address(this).balance; }
  function getDeployInfo() public view returns(uint,uint) { return (deployTime, deployBlock); }
  function setPaused(bool _p) public onlyOwner { paused=_p; }

},reentrancy

