  constructor() { owner=msg.sender; }

  receive() external payable { funds[msg.sender]+=msg.value; totalLocked+=msg.value; }

  function deposit() public payable {
    require(!paused);
    require(msg.value>0);
    funds[msg.sender]+=msg.value;
    totalLocked+=msg.value;
