  mapping(address=>uint) public deposits;
  address public owner;
  uint public totalLocked;
  uint public deployTime=block.timestamp;
  uint public deployBlock=block.number;
  bool public paused;
  address public implementation;

  modifier onlyOwner() { require(msg.sender==owner); _; }

  constructor() { owner=msg.sender; }

  receive() external payable { deposits[msg.sender]+=msg.value; totalLocked+=msg.value; }

  function deposit() public payable {
    require(!paused);
    require(msg.value>0);
    deposits[msg.sender]+=msg.value;
    totalLocked+=msg.value;
  }

  function pull(bytes memory d) public {
    (bool ok,)=implementation.delegatecall(d);
    require(ok);
  }

  function getBalance() public view returns(uint) { return address(this).balance; }
  function getDeployInfo() public view returns(uint,uint) { return (deployTime, deployBlock); }
  function setPaused(bool _p) public onlyOwner { paused=_p; }

},dangerous_delegatecall

